[CmdletBinding()]param();$ErrorActionPreference='Stop';$root=(Resolve-Path (Join-Path $PSScriptRoot '..')).Path;. (Join-Path $root 'tests/helpers/TypedStudioFixture.ps1');$work=Join-Path ([IO.Path]::GetTempPath()) ('phase1-'+[guid]::NewGuid().ToString('N'));New-Item -ItemType Directory $work|Out-Null
function Expect([scriptblock]$Action,[string]$Text){try{&$Action;throw 'expected'}catch{if($_.Exception.Message -eq 'expected'){throw};if($_.Exception.Message -notmatch $Text){throw "Expected $Text; got $($_.Exception.Message)"}}}
try{$a=New-TypedStudioFixture $work 'no-approval' -MissingApproval;Expect {& "$root/scripts/Test-ImplementationPreflight.ps1" -ProjectRoot $a} 'blocked';$b=New-TypedStudioFixture $work 'missing-plan' -Approved -MissingRecords @('IMPLEMENTATION_PLAN.md');Remove-Item (Join-Path $b '.studio/IMPLEMENTATION_PLAN.md');Expect {& "$root/scripts/Test-ImplementationPreflight.ps1" -ProjectRoot $b} 'blocked';$c=New-TypedStudioFixture $work 'valid' -Approved -ExistingRepository;& "$root/scripts/Test-ImplementationPreflight.ps1" -ProjectRoot $c|Out-Null;$docs=New-TypedStudioFixture $work 'docs' -Surfaces @('documentation') -Approved -Runnable:$false;$p=& "$root/scripts/Resolve-SpecialistPlan.ps1" -ProjectRoot $docs;if($p.selected.Count){throw 'Documentation selected implementation role'}}finally{Remove-Item $work -Recurse -Force};Write-Host 'Phase 1 project-state/script integration passed; host-agent and browser runtime unverified.'
